function solve(s: string, order: number[], k: number): number {
    const n = s.length;
    const positions: number[] = [];
    for (let i = 0; i < n; i++) {
        positions.push(i);
    }

    // Preprocess the order to get the positions in the order they are replaced
    const replacedPositions: number[] = [];
    for (const pos of order) {
        replacedPositions.push(pos);
    }

    // Function to count the number of valid substrings
    function countValidSubstrings(replaced: boolean[]): number {
        let count = 0;
        let prevStar = -1;
        let currentCount = 0;

        for (let i = 0; i < n; i++) {
            if (replaced[i]) {
                if (prevStar === -1) {
                    prevStar = i;
                }
                currentCount = i - prevStar + 1;
                count += currentCount;
            } else {
                prevStar = -1;
            }
        }
        return count;
    }

    // Binary search for the minimum time t
    let left = 0;
    let right = n;
    let result = -1;

    while (left <= right) {
        const mid = Math.floor((left + right) / 2);
        const replaced: boolean[] = new Array(n).fill(false);

        for (let i = 0; i < mid; i++) {
            replaced[replacedPositions[i]] = true;
        }

        const validCount = countValidSubstrings(replaced);
        if (validCount >= k) {
            result = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return result;
}

